                int write_r = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        if (r != write_r) {
                            board[write_r][c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_r--;
                    }
                }
            }
        } else if (dir_idx == 2) { // L (Left)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c++;
                    }
                }
            }
        } else { // R (Right)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        if (c != write_c) {
                            board[r][write_c] = board[r][c];
                            board[r][c] = 0;
                        }
                        write_c--;
                    }
                }
            }
        }
    }

    long long calculate_sum_sq_comp_size() const {
        long long total_sq_sum = 0;
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);
        std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr;

        for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
            for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
                if (board[r_start][c_start] != 0 && !visited[r_start][c_start]) {
                    int current_flavor = board[r_start][c_start];
                    long long comp_size = 0;
                    q_arr[0] = {r_start, c_start};
                    visited[r_start][c_start] = true;
                    int head = 0, tail = 1;

                    while (head < tail) {
                        comp_size++;
                        int curr_r = q_arr[head].first;
                        int curr_c = q_arr[head].second;
                        head++;
                        for (int i = 0; i < NUM_DIRECTIONS; ++i) {
                            int nr = curr_r + DR[i];
                            int nc = curr_c + DC[i];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == current_flavor) {
                                visited[nr][nc] = true;
                                q_arr[tail++] = {nr, nc};
                            }
                        }
                    }
                    total_sq_sum += comp_size * comp_size;
                }
            }
        }
        return total_sq_sum;
    }

    // Count empty cells adjacent to occupied cells of each flavor
    // Lower exposure = better defended clusters (wall-hugging helps)
    int calculate_exposure() const {
        int total_exposure = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) {
                    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
                        int nr = r + DR[d];
                        int nc = c + DC[d];
                        if (nr < 0 || nr >= GRID_SIZE || nc < 0 || nc >= GRID_SIZE) {
                            // Wall contact - not exposed on this side (good)
                            continue;
                        }
                        if (board[nr][nc] == 0) {
                            total_exposure++;
                        }
                    }
                }
            }
        }
        return total_exposure;
    }

    // Count different-flavor adjacencies (mixing penalty)
    int count_diff_flavor_adjacencies() const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                int f = board[r][c];
                if (c + 1 < GRID_SIZE && board[r][c + 1] != 0 && board[r][c + 1] != f) count++;
                if (r + 1 < GRID_SIZE && board[r + 1][c] != 0 && board[r + 1][c] != f) count++;
            }
        }
        return count;
    }

    // Compute the score we'd get if we used the actual scoring formula right now
