        // For partial board, use placed counts
        long long denom = 0;
        std::array<int, NUM_FLAVORS + 1> counts{};
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0) counts[board[r][c]]++;
            }
        }
        for (int f = 1; f <= NUM_FLAVORS; ++f) {
            denom += (long long)counts[f] * counts[f];
        }
        if (denom == 0) return 0.0;
        return static_cast<double>(sum_sq) / denom;
    }

